export default "{ lib, buildLinux, fetchurl\n, kernelPatches ? [ ]\n, structuredExtraConfig ? {}\n, extraMeta ? {}\n, argsOverride ? {}\n, ... } @ args:\n\nlet\n  version = \"5.4.177-rt69\"; # updated by ./update-rt.sh\n  branch = lib.versions.majorMinor version;\n  kversion = builtins.elemAt (lib.splitString \"-\" version) 0;\nin buildLinux (args // {\n  inherit version;\n\n  src = fetchurl {\n    url = \"mirror://kernel/linux/kernel/v5.x/linux-${kversion}.tar.xz\";\n    sha256 = \"0wvb5is8rqvfxia1i8lw4yd3fm2bhb6wdl0bdjq90dx7y46wpxqq\";\n  };\n\n  kernelPatches = let rt-patch = {\n    name = \"rt\";\n    patch = fetchurl {\n      url = \"mirror://kernel/linux/kernel/projects/rt/${branch}/older/patch-${version}.patch.xz\";\n      sha256 = \"16m1swkg54cgcgqwl6vifbpfvdf7waigbwi9brafwplb965zq5a2\";\n    };\n  }; in [ rt-patch ] ++ kernelPatches;\n\n  structuredExtraConfig = with lib.kernel; {\n    PREEMPT_RT = yes;\n    # Fix error: unused option: PREEMPT_RT.\n    EXPERT = yes; # PREEMPT_RT depends on it (in kernel/Kconfig.preempt)\n    # Fix error: option not set correctly: PREEMPT_VOLUNTARY (wanted 'y', got 'n').\n    PREEMPT_VOLUNTARY = lib.mkForce no; # PREEMPT_RT deselects it.\n    # Fix error: unused option: RT_GROUP_SCHED.\n    RT_GROUP_SCHED = lib.mkForce (option no); # Removed by sched-disable-rt-group-sched-on-rt.patch.\n  } // structuredExtraConfig;\n\n  extraMeta = extraMeta // {\n    inherit branch;\n  };\n} // argsOverride)\n";
